input.command:
$targets = @(
    "C:\Users\25789\Desktop",
    "C:\Users\25789\Downloads",
    "C:\Users\25789\Documents"
)
$extensions = @("*.zip", "*.exe", "*.msi", "*.docx", "*.pdf", "*.xlsx", "*.jpg", "*.png", "*.mp4", "*.txt", "*.md")

$results = @()
foreach ($dir in $targets) {
    foreach ($ext in $extensions) {
        if (Test-Path $dir) {
            $files = Get-ChildItem -Path $dir -Filter $ext -File -ErrorAction SilentlyContinue
            $groups = $files | Group-Object @{e={$_.Name}}, Length | Where-Object Count -gt 1
            foreach ($g in $groups) {
                $results += [PSCustomObject]@{
                    FileName = $g.Name
                    SizeKB = [math]::Round($g.Group[0].Length / 1KB, 1)
                    Copies = $g.Count
                    Paths = ($g.Group.FullName -join "`n")
                }
            }
        }
    }
}
$results | Sort-Object SizeKB -Descending | Format-Table FileName, SizeKB, Copies -AutoSize

# Also show total count and space
$total = ($results | Measure-Object 'Copies' -Sum).Sum
$extraSpace = ($results | ForEach-Object { ($_.Copies - 1) * ($_.SizeKB * 1KB) } | Measure-Object -Sum).Sum / 1MB
Write-Host "`n=== 汇总 ==="
Write-Host "重复文件组数: $($results.Count)"
Write-Host "重复副本总数(含原始): $total"
Write-Host "可回收空间: $([math]::Round($extraSpace, 1)) MB"
if ($results) {
    Write-Host "`n=== 详细路径 ==="
    $results | Sort-Object SizeKB -Descending | ForEach-Object {
        Write-Host "`n--- $($_.FileName) ($($_.SizeKB) KB, $($_.Copies) 份) ---"
        $_.Paths -split "`n" | ForEach-Object { Write-Host "  $_" }
    }
}

$targets = @(
    "C:\Users\25789\Desktop",
    "C:\Users\25789\Downloads"
)

$results = @()
foreach ($dir in $targets) {
    if (!(Test-Path $dir)) { continue }
    $files = Get-ChildItem -Path $dir -File -ErrorAction SilentlyContinue
    # Group by base name (strip (N) suffix)
    $groups = $files | Group-Object @{
        e={
            $n = $_.BaseName
            $n = $n -replace '\s*\(\d+\)\s*$', ''
            $n = $n -replace '\s+', ' '
            "$($n.ToLower())::$($_.Extension.ToLower())"
        }
    } | Where-Object Count -gt 1

    foreach ($g in $groups) {
        $sorted = $g.Group | Sort-Object Length -Descending
        $first = $sorted[0]
        $others = $sorted[1..$($sorted.Count-1)]
        # Calculate potential savings (keep largest, delete rest)
        $save = ($others | Measure-Object Length -Sum).Sum

        $results += [PSCustomObject]@{
            BaseName = $first.BaseName -replace '\s*\(\d+\)\s*$', ''
            Extension = $first.Extension
            TotalCopies = $g.Count
            Versions = ($sorted | ForEach-Object { "$($_.Name) ($([math]::Round($_.Length/1KB,0)) KB)" }) -join "`n"
            LargestKB = [math]::Round($first.Length/1KB, 0)
            TotalSizeMB = [math]::Round(($sorted | Measure-Object Length -Sum).Sum / 1MB, 1)
            SaveableMB = [math]::Round($save / 1MB, 2)
        }
    }
}

$results = $results | Sort-Object SaveableMB -Descending

if ($results) {
    $totalSave = ($results | Measure-Object SaveableMB -Sum).Sum
    Write-Host "=== 按基础文件名相同的疑似重复文件 ==="
    Write-Host "共 $($results.Count) 组，预估可清理 $([math]::Round($totalSave, 2)) MB`n"
    $results | ForEach-Object {
        Write-Host "--- $($_.BaseName)$($_.Extension) ($($_.TotalCopies) 份, 最大 $($_.LargestKB) KB, 总计 $($_.TotalSizeMB) MB, 可省 $($_.SaveableMB) MB) ---"
        $_.Versions -split "`n" | ForEach-Object { Write-Host "  $_" }
        Write-Host ""
    }
    Write-Host "=== 总计可清理: $([math]::Round($totalSave, 2)) MB ==="
} else {
    Write-Host "未找到疑似重复文件"
}

# Delete exact duplicates (same size, confirmed identical)
$toDelete = @(
    "C:\Users\25789\Desktop\策未来_未来教育品牌旗下全国职业教育培训网校_未来教育是一家研究计算机等级考试、英语等级考试、医学考试、日语考试的教育机构，提供给考生最新考试资讯、考试动态、报名查分、模拟试题、在线咨询、最新考试题库购买，为考生提供最全面的帮助! (1).mp4",
    "C:\Users\25789\Desktop\KHY-Quant-android-release (1).apk",
    "C:\Users\25789\Desktop\S22631742820+孔浩原-基于量化交易策略的企业财务绩效研究 ——以螺纹钢主力合约为例 (1).docx",
    "C:\Users\25789\Desktop\tnix-main (1).zip",
    "C:\Users\25789\Desktop\22631742820孔浩原 开题报告 (1).htm"
)

# Also delete 0 KB empty files
$toDelete += @(
    "C:\Users\25789\Desktop\README (1).md",
    "C:\Users\25789\Desktop\Trae-Setup-x64 (1).exe",
    "C:\Users\25789\Desktop\KHY-Quant-Setup-8.0.0 (1).exe",
    "C:\Users\25789\Desktop\KHY-Quant-Setup-8.0.0 (2).exe",
    "C:\Users\25789\Desktop\KHY-Quant-Setup-8.0.0 (3).exe"
)

$deleted = 0
$errors = @()
foreach ($f in $toDelete) {
    if (Test-Path $f) {
        Remove-Item -Path $f -Force -ErrorAction SilentlyContinue
        if (Test-Path $f) {
            $errors += "删除失败: $f"
        } else {
            $deleted++
            Write-Host "✓ 已删除: $(Split-Path $f -Leaf)"
        }
    } else {
        Write-Host "~ 文件不存在: $(Split-Path $f -Leaf)"
    }
}
Write-Host "`n完成：成功删除 $deleted 个文件"
if ($errors) { $errors | ForEach-Object { Write-Warning $_ } }

# Find where Desktop actually points
$desktop = [Environment]::GetFolderPath('Desktop')
Write-Host "Shell Desktop: $desktop"

$userDesktop = [Environment]::GetFolderPath('DesktopDirectory')
Write-Host "DesktopDirectory: $userDesktop"

# Also check user profile desktop
$profileDesktop = "$env:USERPROFILE\Desktop"
Write-Host "Profile Desktop: $profileDesktop"
if (Test-Path $profileDesktop) {
    $target = (Get-Item $profileDesktop -Force).Target
    if ($target) { Write-Host " -> Junction/Link target: $target" }
}

# Check the C:\Users\25789\Desktop
Write-Host "`nC:\Users\25789\Desktop exists: $(Test-Path 'C:\Users\25789\Desktop')"
if (Test-Path 'C:\Users\25789\Desktop' -PathType Container) {
    $items = Get-ChildItem 'C:\Users\25789\Desktop' -Force
    Write-Host "C:\Desktop has $($items.Count) items (hidden included)"
    $items | Select-Object -First 5 Name | ForEach-Object { Write-Host "  $($_.Name)" }
}

Write-Host "`nD:\HuaweiMoveData\Users\25789\Desktop exists: $(Test-Path 'D:\HuaweiMoveData\Users\25789\Desktop')"
if (Test-Path 'D:\HuaweiMoveData\Users\25789\Desktop' -PathType Container) {
    $items = Get-ChildItem 'D:\HuaweiMoveData\Users\25789\Desktop' -Force
    Write-Host "D:\Desktop has $($items.Count) items"
}

$targets = @(
    "C:\Users\25789\Desktop",
    "C:\Users\25789\Downloads",
    "C:\Users\25789\Documents",
    "C:\Users\25789\Pictures",
    "C:\Users\25789\Videos",
    "C:\Users\25789\Music",
    "C:\Users\25789\src",
    "C:\Users\25789\sql",
    "C:\Users\25789\unit_tests",
    "C:\Users\25789\gitee",
    "C:\Users\25789\Cloud",
    "C:\Users\25789\khy-tc",
    "C:\Users\25789\khy-quant-main"
)

$results = @()
foreach ($dir in $targets) {
    if (!(Test-Path $dir)) { continue }
    $files = Get-ChildItem -Path $dir -File -Recurse -ErrorAction SilentlyContinue -Depth 3
    $groups = $files | Group-Object @{
        e={
            $n = $_.BaseName
            $n = $n -replace '\s*\(\d+\)\s*$', ''
            $n = $n -replace '\s+', ' '
            "$($n.ToLower())::$($_.Extension.ToLower())"
        }
    } | Where-Object Count -gt 1

    foreach ($g in $groups) {
        $sorted = $g.Group | Sort-Object Length -Descending
        $others = $sorted[1..$($sorted.Count-1)]
        $save = ($others | Measure-Object Length -Sum).Sum
        if ($save -eq 0 -and $g.Count -le 2) { continue }  # skip 0-byte pairs

        $results += [PSCustomObject]@{
            BaseName = $sorted[0].BaseName -replace '\s*\(\d+\)\s*$', ''
            Extension = $sorted[0].Extension
            TotalCopies = $g.Count
            SaveMB = [math]::Round($save / 1MB, 2)
            Versions = ($sorted | ForEach-Object { "$($_.FullName) ($([math]::Round($_.Length/1KB,0)) KB)" }) -join "`n"
        }
    }
}

$results = $results | Sort-Object SaveMB -Descending

if ($results) {
    $totalSave = ($results | Measure-Object SaveMB -Sum).Sum
    Write-Host "=== C 盘疑似重复文件 ($($results.Count) 组) ==="
    Write-Host "预估可清理: $([math]::Round($totalSave, 2)) MB`n"
    $results | ForEach-Object {
        Write-Host "[$($_.SaveMB) MB] $($_.BaseName)$($_.Extension) ($($_.TotalCopies) 份)"
        $_.Versions -split "`n" | ForEach-Object { Write-Host "   $_" }
        Write-Host ""
    }
} else {
    Write-Host "C 盘未发现明显的重复文件"
}
